const input = $input.first().json;
const action = input.action || '';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.youtube&cred_key=eq.youtube_api_key&select=cred_value',
  headers: pgHeaders
});
if (!creds || !creds[0] || !creds[0].cred_value) {
  return [{ json: { error: 'YouTube API key not configured. Use add_credential to set it up.' } }];
}
const key = creds[0].cred_value;
const API = 'https://www.googleapis.com/youtube/v3';

function formatDuration(iso) {
  if (!iso) return '';
  const m = iso.match(/^PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?$/);
  if (!m) return iso;
  const h = parseInt(m[1] || '0');
  const mm = parseInt(m[2] || '0');
  const s = parseInt(m[3] || '0');
  if (h > 0) return h + 'h ' + mm + 'm ' + s + 's';
  if (mm > 0) return mm + 'm ' + s + 's';
  return s + 's';
}

function formatNum(n) {
  if (n == null) return '';
  const num = parseInt(n);
  if (isNaN(num)) return String(n);
  if (num >= 1000000000) return (num / 1000000000).toFixed(1) + 'B';
  if (num >= 1000000) return (num / 1000000).toFixed(1) + 'M';
  if (num >= 1000) return (num / 1000).toFixed(1) + 'K';
  return String(num);
}

async function resolveChannelId(idOrHandle) {
  if (!idOrHandle) return null;
  const s = String(idOrHandle).trim();
  if (s.startsWith('UC') && s.length === 24) return s;
  const handle = s.startsWith('@') ? s : '@' + s;
  const data = await helpers.httpRequest({
    method: 'GET',
    url: API + '/channels?part=id&forHandle=' + encodeURIComponent(handle) + '&key=' + key
  });
  if (data.items && data.items[0]) return data.items[0].id;
  return null;
}

// === search_videos ===
if (action === 'search_videos') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required.' } }];
  const limit = Math.min(parseInt(input.limit) || 5, 25);
  const order = ['relevance', 'date', 'viewCount', 'rating'].includes(input.order) ? input.order : 'relevance';

  try {
    const url = API + '/search?part=snippet&type=video&q=' + encodeURIComponent(query) + '&maxResults=' + limit + '&order=' + order + '&key=' + key;
    const data = await helpers.httpRequest({ method: 'GET', url });
    const items = data.items || [];
    if (items.length === 0) return [{ json: { result: 'No videos found for: ' + query } }];

    let out = 'Top ' + items.length + ' videos for "' + query + '" (' + (data.pageInfo && data.pageInfo.totalResults || '?') + ' total, sort: ' + order + '):\n\n';
    for (const it of items) {
      const s = it.snippet;
      const vid = it.id && it.id.videoId;
      out += '**' + s.title + '**\n';
      out += '  Channel: ' + s.channelTitle + '\n';
      out += '  Published: ' + s.publishedAt.substring(0, 10) + '\n';
      out += '  ID: ' + vid + '\n';
      out += '  URL: https://youtube.com/watch?v=' + vid + '\n';
      if (s.description) {
        const desc = s.description.substring(0, 150);
        if (desc) out += '  ' + desc + (s.description.length > 150 ? '...' : '') + '\n';
      }
      out += '\n';
    }
    if (out.length > 5000) out = out.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'YouTube search failed: ' + (err.message || err) } }];
  }

// === get_video ===
} else if (action === 'get_video') {
  const videoId = input.video_id;
  if (!videoId) return [{ json: { error: 'Parameter "video_id" is required (e.g. vcvRVlc_VFg from search_videos or the v= part of a YouTube URL).' } }];

  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: API + '/videos?part=snippet,statistics,contentDetails&id=' + encodeURIComponent(videoId) + '&key=' + key
    });
    const v = data.items && data.items[0];
    if (!v) return [{ json: { error: 'Video not found: ' + videoId } }];
    const s = v.snippet, st = v.statistics || {}, cd = v.contentDetails || {};
    let out = '**' + s.title + '**\n';
    out += 'Channel: ' + s.channelTitle + ' (' + s.channelId + ')\n';
    out += 'Published: ' + s.publishedAt + '\n';
    out += 'Duration: ' + formatDuration(cd.duration) + '\n';
    out += 'Views: ' + formatNum(st.viewCount) + '\n';
    if (st.likeCount) out += 'Likes: ' + formatNum(st.likeCount) + '\n';
    if (st.commentCount) out += 'Comments: ' + formatNum(st.commentCount) + '\n';
    out += 'URL: https://youtube.com/watch?v=' + v.id + '\n';
    if (s.tags && s.tags.length > 0) out += 'Tags: ' + s.tags.slice(0, 10).join(', ') + '\n';
    if (s.description) {
      const desc = s.description.length > 2000 ? s.description.substring(0, 2000) + '...' : s.description;
      out += '\nDescription:\n' + desc + '\n';
    }
    if (out.length > 5000) out = out.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'YouTube get_video failed: ' + (err.message || err) } }];
  }

// === get_channel ===
} else if (action === 'get_channel') {
  const ch = input.channel_id || input.handle;
  if (!ch) return [{ json: { error: 'Provide either "channel_id" (UC...) or "handle" (@...).' } }];
  const isHandle = String(ch).startsWith('@') || (!String(ch).startsWith('UC'));
  const param = isHandle ? ('forHandle=' + encodeURIComponent(String(ch).startsWith('@') ? ch : '@' + ch)) : ('id=' + encodeURIComponent(ch));

  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: API + '/channels?part=snippet,statistics,contentDetails&' + param + '&key=' + key
    });
    const c = data.items && data.items[0];
    if (!c) return [{ json: { error: 'Channel not found: ' + ch } }];
    const st = c.statistics || {};
    let out = '**' + c.snippet.title + '**\n';
    out += 'ID: ' + c.id + '\n';
    if (c.snippet.customUrl) out += 'Handle: ' + c.snippet.customUrl + '\n';
    if (c.snippet.country) out += 'Country: ' + c.snippet.country + '\n';
    out += 'Published: ' + c.snippet.publishedAt.substring(0, 10) + '\n';
    if (st.subscriberCount) out += 'Subscribers: ' + formatNum(st.subscriberCount) + '\n';
    if (st.viewCount) out += 'Total views: ' + formatNum(st.viewCount) + '\n';
    if (st.videoCount) out += 'Video count: ' + st.videoCount + '\n';
    out += 'URL: https://youtube.com/channel/' + c.id + '\n';
    if (c.snippet.description) {
      const desc = c.snippet.description.length > 1000 ? c.snippet.description.substring(0, 1000) + '...' : c.snippet.description;
      out += '\nAbout:\n' + desc + '\n';
    }
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'YouTube get_channel failed: ' + (err.message || err) } }];
  }

// === list_channel_videos ===
} else if (action === 'list_channel_videos') {
  const ch = input.channel_id || input.handle;
  if (!ch) return [{ json: { error: 'Provide either "channel_id" (UC...) or "handle" (@...).' } }];
  const limit = Math.min(parseInt(input.limit) || 5, 20);

  try {
    const channelId = await resolveChannelId(ch);
    if (!channelId) return [{ json: { error: 'Channel not found: ' + ch } }];

    const chData = await helpers.httpRequest({
      method: 'GET',
      url: API + '/channels?part=snippet,contentDetails&id=' + channelId + '&key=' + key
    });
    const c = chData.items && chData.items[0];
    if (!c) return [{ json: { error: 'Channel not found: ' + ch } }];
    const uploads = c.contentDetails && c.contentDetails.relatedPlaylists && c.contentDetails.relatedPlaylists.uploads;
    if (!uploads) return [{ json: { error: 'No uploads playlist for channel ' + channelId + '.' } }];

    const pl = await helpers.httpRequest({
      method: 'GET',
      url: API + '/playlistItems?part=snippet&playlistId=' + uploads + '&maxResults=' + limit + '&key=' + key
    });
    const items = pl.items || [];
    if (items.length === 0) return [{ json: { result: 'No videos on channel ' + c.snippet.title + '.' } }];

    let out = 'Latest ' + items.length + ' videos from **' + c.snippet.title + '**:\n\n';
    for (const it of items) {
      const s = it.snippet;
      const vid = s.resourceId && s.resourceId.videoId;
      out += '[' + s.publishedAt.substring(0, 10) + '] ' + s.title + '\n';
      out += '  ID: ' + vid + '\n';
      out += '  URL: https://youtube.com/watch?v=' + vid + '\n\n';
    }
    if (out.length > 5000) out = out.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'YouTube list_channel_videos failed: ' + (err.message || err) } }];
  }

} else {
  return [{ json: { error: 'Unknown action: "' + action + '". Available: search_videos, get_video, get_channel, list_channel_videos.' } }];
}
